#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 青少年编程教育.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年编程教育"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 课程设计与年龄匹配
  9.2 竞赛路线评估与规划
  9.3 工具选型与技术栈
  9.4 政策合规审查
  9.5 教师招聘与培训评估
  9.6 家长沟通与预期管理
  9.7 AI 工具整合评估

背后的心智模型:
  • 制作即学习 (Making Is Learning): 编程教育的核心不是教「编程语言语法」, 而是让学生通过创造可分享的外部作品来建构内部知识 — Papert 的建构主义 (constructionism) 是整个领域的哲学根基
  • 低地板、高天花板、宽墙壁 (Low Floor, High Ceiling, Wide Walls): 好的编程教育工具必须同时满足三个维度 — 入门门槛低 (low floor, 6 岁能开始)、能力上限高 (high ceiling, 能做复杂项目)、创作方向广 (wide walls, 不限于一种
  • 计算思维不等于编程 (CT ≠ Coding): 计算思维 (Computational Thinking) 是抽象、分解、模式识别、算法设计四种跨学科思维能力的组合 — 它的价值不在于「写出可运行的代码」, 而在于用计算方式思考任何领域的问题. 把

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "课程设计与年龄匹配"
  "竞赛路线评估与规划"
  "工具选型与技术栈"
  "政策合规审查"
  "教师招聘与培训评估"
  "家长沟通与预期管理"
  "AI 工具整合评估"
)
declare -a DIM_QUESTIONS=(
  "目标学生年龄段 + 认知发展阶段 + 已有编程经验 + 学习目标 (兴趣/竞赛/升学)"
  "学生数学基础 + 编程能力 + 投入意愿 + 目标赛事 (CSP-J/S / NOIP / NOI / IOI)"
  "教学目标 (启蒙/进阶/竞赛/创客) × 学生年龄 × 预算 × 教师技术能力"
  "办学形式 (线上/线下/进校) × 地域 × 课程类型 (学科/素质) × 收费模式"
  "CS 背景比例 + 教学经验 + 编程能力 (能否独立写中等复杂度项目) + 与学生互动能力"
  "家长核心诉求 (升学/兴趣/能力) + 对编程教育的认知水平 + 付费意愿"
  "AI 工具类型 (辅助编程/自动评测/对话辅导) × 学生年龄 × 教学目标 × 竞赛规则"
)
declare -a DIM_SOURCES=(
  "Piaget 认知发展理论 + CSTA K-12 CS Standards 年级对齐表 + 中国信息科技课标 + Code.org 课程年龄推荐"
  "洛谷题目难度评级 + CCF 官网赛事日历 + 历年真题分析 + 省选/NOI 录取分数线 (各省不同)"
  "工具官方文档 + CSTA 推荐工具列表 + 教育技术评测 (EdSurge/Common Sense Media) + 硬件价格比较"
  "教育部双减政策文件 + 各地教育局实施细则 + 校外培训行政处罚暂行办法 (2023) + COPPA/GDPR (海外市场)"
  "CSTA 教师标准 + ISTE 认证体系 + 中国信息科技教师资格要求 + 行业薪资数据"
  "家长常见问题库 (本 skill playbook 8 提供框架) + 竞赛政策最新动态 + 行业续费率数据"
  "Khanmigo 负责任 AI 框架 + IOI 2024+ AI 使用规定 + Code.org Hour of AI + 教师反馈"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「推荐: {年龄段} → {工具} + {教学法} + {评价方式}; 不推荐: {工具} (原因: {认知发展不匹配}); 过渡方案: {桥接课程}」"
  "「当前水平: {洛谷评级}; 目标赛事: {赛事} (约 {难度}); 训练计划: {知识板块序列} × {每周时长}; 预期时间: {月}; 风险: {政策变化/心理压力}」"
  "「推荐: {工具栈}; 人均成本: {金额}; 教师培训需求: {时长}; 替代方案: {低成本选项}; 避坑: {不推荐的工具及原因}」"
  "「合规状态: {合规/灰区/违规}; 关键要求: {3-5 条}; 最高风险: {预付费/资质/内容审查}; 建议: {合规路径}」"
  "「当前教师画像: {背景分布}; 缺口: {N 人 × 能力维度}; 培训方案: {时长 × 内容}; 预算: {人均}; 留存策略: {激励机制}」"
  "「家长核心问题: {列表}; 诚实回答: {每个问题的事实+限制}; 不应承诺: {列表}; 展示方式: {作品/视频/竞赛成绩}」"
  "「AI 适用场景: {列表}; 禁用场景: {列表, 特别是竞赛}; 护栏设计: {技术+流程}; human-in-the-loop: {教师审核机制}」"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
